import { useEffect } from 'react';
import mystyle from './EmpTask.module.css'
import { useState } from 'react';
import axios from 'axios';
import { useParams } from 'react-router';

const EmpTask = () => {

    const { id } = useParams();

    console.log(id)
    console.log("this data i got from storg")

    const [data, setData] = useState([]);

    useEffect(() => {

        console.log("this is the emp data id in emptask page got it :" + id)

        axios.post(`https://task-tracker-64ei.onrender.com/empalldata/${id}`).then((success) => {
            console.log(success)
            setData(success.data)
        }).catch((error) => {
            console.log(error)
        })
    }, [axios])


    const getAccept = (id) => {
        console.log("task accept" + id)

        axios.post(`https://task-tracker-64ei.onrender.com/changetaskstatus/${id}`).then((success) => {
            console.log((success))
        }).catch((error) => {
            console.log(error)
        })
    }

    const getCancel = (id) => {
        console.log(id);

        axios.post(`https://task-tracker-64ei.onrender.com/canceltask/${id}`).then((success) => {
            console.log(success)
        }).catch((error) => {
            console.log(error)
        })
    }

    const getDone = (id) => {
        console.log("task done" + id)


        axios.post(`https://task-tracker-64ei.onrender.com/donestatus/${id}`).then((success) => {
            console.log((success))
        }).catch((error) => {
            console.log(error)
        })
    }

    return (

        <div className={mystyle.main}>

            <h2>Employee Task  Data</h2>
            <div className={mystyle.sub}>
                {
                    data.map((d, index) => {
                        return (
                            <div key={index} className={mystyle.emp} >

                                {d.taskData.map((t) => {

                                    console.log(t._id)
                                    return (
                                        <div className={mystyle.emp1}  >

                                            <p>id: {t._id}</p>
                                            <p>Email: {t.email}</p>
                                            <p>Task: {t.task}</p>
                                            <p>Time: {t.time}</p>

                                            {
                                                t.tstatus === "0" ? (
                                                    <p>
                                                        <button
                                                            className={mystyle.btn1}
                                                            onClick={() => getAccept(t._id)}
                                                        >
                                                            Accept
                                                        </button>

                                                        <button className={mystyle.cnlbtn} onClick={() => getCancel(t._id)}>
                                                            Cancel
                                                        </button>
                                                    </p>


                                                ): t.tstatus === "3" ?(
                                                  
                                                    <button  className={mystyle.btn4} disabled>Canceled</button>
                                                
                                                ) : t.tstatus === "1" ? (
                                                    <button
                                                        className={mystyle.btn2}
                                                        onClick={() => getDone(t._id)}
                                                    >
                                                        Done
                                                    </button>
                                                ) : (
                                                    <button className={mystyle.btn3} disabled>
                                                        Completed
                                                    </button>
                                                )
                                            }

                                        </div>
                                    )



                                })}



                            </div>
                        )
                    })
                }


            </div>

        </div >
    )
}
export default EmpTask;