
import { useEffect, useState } from 'react'
import mystyle from './TeamLeaderdash.module.css'
import { useParams } from 'react-router'
import axios from 'axios';
import { PieChart, Pie, Cell, Tooltip, Legend } from "recharts";



const TeamLeaderdash = () => {

    const { id } = useParams();

    const [data, setData] = useState([]);

    useEffect(() => {

        axios.post(`http://localhost:5000/teamempdata/${id}`).then((success) => {
            console.log(success)
            setData(success.data)
        }).catch((error) => {
            console.log(error)
        })

    }, [])

    const toaltask = data.length;

    const panddingtask = data.filter((p) => { return p.tstatus === "0" }).length;
    console.log(typeof panddingtask);

    const completedtask = data.filter((c) => { return c.tstatus === "2" }).length;
    console.log(typeof completedtask);

    const doing = data.filter((d) => { return d.tstatus === "1" }).length;
    console.log(typeof doing)

    const canceled = data.filter((c)=>{ return c.tstatus === "3" }).length;

    const pdata = [
        { name: "Pending", value: Number(panddingtask) },
        { name: "Completed", value: Number(completedtask) },
        { name: "In Progress", value: Number(doing) },
        { name: "Canceled", value: Number(canceled) }
    ];

    const COLORS = ["#f59e0b", "#22c55e", "#3b82f6", "#ef4444"];

    return (
        <div className={mystyle.main}>
            <div className={mystyle.di1}>
                <div className={mystyle.di1sub1}>
                    <h4>My Productivity</h4>
                    <p>Focus on your goals Alex. You hava 5 tasks due in the next 48 hours.</p>
                </div>
                <div className={mystyle.di1sub2}>
                    <p>my day</p>
                    <p>Reports</p>
                </div>
            </div>
            <div className={mystyle.di2}>

                <div className={mystyle.di2sub3}>
                    <div className={mystyle.di2sub3d1}>
                        <p><i class="bi bi-stopwatch"></i></p>
                        <p><i class="bi bi-plus"></i>2h</p>
                    </div>
                    <p className={mystyle.di2sub3p1}>Toatl Task</p>
                    <p className={mystyle.di2sub3p2}>{toaltask}</p>
                </div>
                <div className={mystyle.di2sub1}>
                    <div className={mystyle.di2sub1d1}>
                        <p><i class="bi bi-check2-circle"></i></p>
                        <p>85%</p>
                    </div>
                    <p className={mystyle.di2sub1p1}>Tasks Completed</p>
                    <p className={mystyle.di2sub1p2}>{completedtask}</p>
                </div>
                <div className={mystyle.di2sub2}>
                    <div className={mystyle.di2sub2d1}>
                        <p><i class="bi bi-clock"></i></p>
                        <p><i class="bi bi-arrow-up-short"></i></p>
                    </div>
                    <p className={mystyle.di2sub2p1}>Pending Items</p>
                    <p className={mystyle.di2sub2p2}>{panddingtask}</p>
                </div>

                <div className={mystyle.di2sub4}>
                    <div className={mystyle.di2sub4d1}>
                        <p><i class="bi bi-arrow-up-right"></i></p>
                        <p>+5%</p>
                    </div>
                    <p className={mystyle.di2sub4p1}>task In-Progress</p>
                    <p className={mystyle.di2sub4p2}>{doing}</p>
                </div>
            </div>
            <div>
                <PieChart width={600} height={500}>
                    <Pie
                        data={pdata}
                        cx="50%"
                        cy="50%"
                        outerRadius={180}
                        dataKey="value"
                        nameKey="name"
                        label
                    >
                        {pdata.map((entry, index) => (
                            <Cell
                                key={index}
                                fill={COLORS[index % COLORS.length]}
                            />
                        ))}
                    </Pie>

                    <Tooltip />
                    <Legend />
                </PieChart>
            </div>
        </div>
    )
}

export default TeamLeaderdash;