
import { useNavigate, useParams } from 'react-router'
import mystyle from './StBody.module.css'
import { useEffect, useState } from 'react';
import axios from 'axios';



const StBody = () => {

    const { id } = useParams();

    console.log("this is on the emp data data" + id)

    const navigate = useNavigate();

    const [data, setData] = useState([])

    useEffect(() => {

        axios.post(`http://localhost:5000/teamempdata/${id}`).then((success) => {
            console.log(success)
            setData(success.data)
        }).catch((error) => {
            console.log(error)
        })

    }, [axios])

    const getId = (d) => {

        let tid = d.tid
        let id = d._id
        console.log(tid)
        console.log(id)


        let email = d.email;
        let task = d.task;
        let time = d.time;
        let status = d.status;

        console.log("i got to edit data" + id + "and" + tid)
        navigate(`/tteam/${tid}/edittask/${id}`, { state: { Email: email, Task: task, Time: time, Status: status, Tid: tid } })

    }

    const getDelid = (id) => {
        console.log(id)
        console.log("this is the delete is i got after click the del button")

        axios.post(`http://localhost:5000/deletetask/${id}`).then((success) => {
            console.log(success)
        }).catch((error) => {
            console.log(error)
        })
    }

    return (
        <div className={mystyle.main}>
            <h1>Employee Data </h1>

            <table className={mystyle.table}>
                <thead>
                    <tr>
                        <th>Id</th>
                        <th>Email</th>
                        <th>Task</th>
                        <th>Time</th>
                        <th>Active</th>
                        <th>Status</th>
                        <th>Actions</th>
                    </tr>
                </thead>

                <tbody>
                    {data.map((d, index) => {
                        const deadline = new Date(d.time);
                        const currentDate = new Date();



                        return (
                            <tr key={index}>
                                <td>{d._id}</td>
                                <td>{d.email}</td>
                                <td>{d.task}</td>
                                <td>{d.time}</td>
                                <td>{d.dstatus}</td>
                                <td>{d.tstatus === "0" ? (<p className={mystyle.panddi} key={id}> <span>pandding</span></p>) :d.tstatus==="3" ? (<p className={mystyle.cantask} key={id}> <span>Canceled</span></p>) : d.tstatus === "1" && currentDate < deadline ? (<p className={mystyle.acce} key={id}> <span>Accepted</span></p>) : d.tstatus === "1" && currentDate > deadline ? (<p className={mystyle.delay} key={id}> <span>Delayed</span></p>) : d.tstatus === "2" && currentDate <= deadline ? (<p className={mystyle.done} key={id}> <span>completed</span></p>) : (<p className={mystyle.done} key={id}> <span>LateCompleted</span></p>)}</td>
                                <td>
                                    <button
                                        className={mystyle.btn1}
                                        onClick={() => getId(d)}
                                    >
                                        <i className="bi bi-pen"></i>
                                    </button>

                                    <button
                                        className={mystyle.btn2}
                                        onClick={() => getDelid(d._id)}
                                    >
                                        <i className="bi bi-trash"></i>
                                    </button>
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>

        </div >
    )
}


export default StBody;